module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output reg [31:0] yout,
    output reg done
);

reg [15:0] a, b;
reg [31:0] product;
reg [4:0] count;
reg [1:0] state;

localparam IDLE = 2'b00;
localparam SHIFT_ACC = 2'b01;
localparam DONE = 2'b10;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a <= 0;
        b <= 0;
        product <= 0;
        count <= 0;
        state <= IDLE;
        done <= 0;
        yout <= 0;
    end else begin
        case (state)
            IDLE: begin
                if (start) begin
                    a <= ain;
                    b <= bin;
                    product <= 0;
                    count <= 16;
                    state <= SHIFT_ACC;
                    done <= 0;
                end
            end
            SHIFT_ACC: begin
                if (count > 0) begin
                    if (b[0]) begin
                        product <= product + (a << (16 - count));
                    end
                    b <= b >> 1;
                    count <= count - 1;
                end else begin
                    state <= DONE;
                end
            end
            DONE: begin
                yout <= product;
                done <= 1;
                state <= IDLE;
            end
        endcase
    end
end

endmodule
